    if line.startswith('#') or not line:
        continue
    # Parse package name and version
    match = re.match(r'([a-zA-Z0-9_.-]+)\s*(==|>=|<=|!=|>|<)\s*([a-zA-Z0-9.*]+)', line)
    if match:
        name = match.group(1)
        op = match.group(2)
        ver = match.group(3)
        packages.append((name, op, ver))
    else:
        name = re.match(r'([a-zA-Z0-9_.-]+)', line)
        if name:
            packages.append((name.group(1), '', ''))

