{"command": "# Get the full list of PyMuPDF releases and check all for cp313
curl -s "https://pypi.org/pypi/PyMuPDF/json" | python3 -c "
import json, sys
data = json.load(sys.stdin)
releases = sorted(data['releases'].keys(), key=lambda x: [int(p) for p in x.split('.')])
# Check each release for cp313 wheels
for ver in releases[-20:]:  # last 20 versions
    for url_info in data['releases'][ver]:
        if url_info.get('packagetype') == 'bdist_wheel' and 'cp313' in url_info.get('filename', ''):
            print(f'PyMuPDF {ver}: HAS cp313 wheel')
            break
    else:
        pass  # No cp313 wheel
# Let me also check if there are any cp313 wheels at all
has_any_cp313 = False
for ver, urls in data['releases'].items():
    for url_info in urls:
        if url_info.get('packagetype') == 'bdist_wheel' and 'cp313' in url_info.get('filename', ''):
            if not has_any_cp313:
                print(f'First PyMuPDF version with cp313: {ver}')
                has_any_cp313 = True
if not has_any_cp313:
    print('NO PyMuPDF version has cp313 wheels')
    # Show available Python tags across all versions
    py_tags = set()
    for ver, urls in data['releases'].items():
        for url_info in urls:
            if url_info.get('packagetype') == 'bdist_wheel':
                fn = url_info['filename']
                parts = fn.split('-')
                for p in parts:
                    if p.startswith('cp') and len(p) <= 6:
                        py_tags.add(p)
    print('All Python tags:', sorted(py_tags))
""}

